Here's the result of running `cat -n` on a snippet of server/kimi.ts
     1→/**
     2→ * Kimi AI (Moonshot) provider — used as the FINAL fallback in the AI chain:
     3→ * Gemini (free 3M/day) → Groq (key pool) → Kimi (paid, always available)
     4→ *
     5→ * Token budget strategy:
     6→ *   - Customer pool:  70% of daily budget  (high traffic, advisor/support)
     7→ *   - Employee pool:  30% of daily budget  (staff assistant, lower volume)
     8→ *
     9→ * Model: moonshot-v1-8k  (cheapest, fast, good Arabic)
    10→ * API:   https://api.moonshot.cn/v1  (OpenAI-compatible)
    11→ */
    12→
    13→interface ChatMessage {
    14→  role: "system" | "user" | "assistant";
    15→  content: string;
    16→}
    17→
    18→const KIMI_API_KEY = (process.env.KIMI_API_KEY || "").trim();
    19→const KIMI_BASE    = "https://api.moonshot.cn/v1/chat/completions";
    20→const KIMI_MODEL   = "moonshot-v1-8k";
    21→
    22→// ─── Daily token budget tracking ───────────────────────────────────────────
    23→// Reset every UTC midnight. We track estimate only — Kimi charges per actual
    24→// usage but we cap to avoid surprise bills.
    25→const DAILY_BUDGET = {
    26→  customer: 17_500_000,   // 70% of 25M
    27→  employee:  7_500_000,   // 30% of 25M
    28→};
    29→
    30→const usedTokens: Record<"customer" | "employee", number> = {
    31→  customer: 0,
    32→  employee: 0,
    33→};
    34→let budgetResetAt = todayMidnightUTC();
    35→
    36→function todayMidnightUTC(): number {
    37→  const d = new Date();
    38→  d.setUTCHours(0, 0, 0, 0);
    39→  return d.getTime() + 86_400_000; // next midnight
    40→}
    41→
    42→function checkAndResetBudget() {
    43→  if (Date.now() >= budgetResetAt) {
    44→    usedTokens.customer = 0;
    45→    usedTokens.employee = 0;
    46→    budgetResetAt = todayMidnightUTC();
    47→    console.log("[Kimi] Daily token budget reset");
    48→  }
    49→}
    50→
    51→export function isKimiConfigured(): boolean {
    52→  return !!KIMI_API_KEY;
    53→}
    54→
    55→/** Estimated tokens (very rough: 1 token ≈ 4 chars for mixed Arabic/English) */
    56→function estimateTokens(messages: ChatMessage[], maxTokens: number): number {
    57→  const promptChars = messages.reduce((acc, m) => acc + m.content.length, 0);
    58→  return Math.ceil(promptChars / 4) + maxTokens;
    59→}
    60→
    61→export function kimiRemainingBudget(audience: "customer" | "employee") {
    62→  checkAndResetBudget();
    63→  return Math.max(0, DAILY_BUDGET[audience] - usedTokens[audience]);
    64→}
    65→
    66→export function kimiBudgetStatus() {
    67→  checkAndResetBudget();
    68→  return {
    69→    customer: {
    70→      used: usedTokens.customer,
    71→      budget: DAILY_BUDGET.customer,
    72→      pct: Math.round((usedTokens.customer / DAILY_BUDGET.customer) * 100),
    73→    },
    74→    employee: {
    75→      used: usedTokens.employee,
    76→      budget: DAILY_BUDGET.employee,
    77→      pct: Math.round((usedTokens.employee / DAILY_BUDGET.employee) * 100),
    78→    },
    79→    resetsAt: new Date(budgetResetAt).toISOString(),
    80→  };
    81→}
    82→
    83→/**
    84→ * Call Kimi chat API. Returns text or throws.
    85→ * audience controls which budget pool is debited.
    86→ */
    87→// Language guard injected before every call to prevent Chinese leaking into Arabic/English replies.
    88→const LANG_GUARD: ChatMessage = {
    89→  role: "system",
    90→  content: "CRITICAL RULE: You MUST reply ONLY in Arabic or English as instructed. NEVER use Chinese, Japanese, Korean, or any other language. If the prompt is in Arabic, reply in Arabic only. If in English, reply in English only. No Chinese characters under any circumstances.",
    91→};
    92→
    93→export async function kimiChat(
    94→  messages: ChatMessage[],
    95→  maxTokens = 1024,
    96→  audience: "customer" | "employee" = "customer",
    97→): Promise<string> {
    98→  if (!KIMI_API_KEY) throw new Error("KIMI_API_KEY not configured");
    99→
   100→  checkAndResetBudget();
   101→  // Prepend the language guard to every call
   102→  const messagesWithGuard = [LANG_GUARD, ...messages];
   103→  const estimated = estimateTokens(messagesWithGuard, maxTokens);
   104→  if (estimated > kimiRemainingBudget(audience)) {
   105→    throw new Error(`[Kimi] Daily ${audience} budget exhausted (${usedTokens[audience].toLocaleString()} / ${DAILY_BUDGET[audience].toLocaleString()} tokens used)`);
   106→  }
   107→
   108→  const res = await fetch(KIMI_BASE, {
   109→    method: "POST",
   110→    headers: {
   111→      "Content-Type": "application/json",
   112→      Authorization: `Bearer ${KIMI_API_KEY}`,
   113→    },
   114→    body: JSON.stringify({
   115→      model: KIMI_MODEL,
   116→      messages: messagesWithGuard,
   117→      max_tokens: maxTokens,
   118→      temperature: 0.4,
   119→    }),
   120→  });
   121→
   122→  if (!res.ok) {
   123→    const txt = await res.text();
   124→    console.error(`[Kimi] HTTP ${res.status}:`, txt.slice(0, 200));
   125→    throw new Error(`Kimi API error ${res.status}: ${txt.slice(0, 100)}`);
   126→  }
   127→
   128→  const data = await res.json();
   129→  const text: string = data?.choices?.[0]?.message?.content || "";
   130→
   131→  // Debit estimated tokens from pool
   132→  usedTokens[audience] += estimated;
   133→  console.log(`[Kimi] ${audience} used ~${estimated} tokens (total today: ${usedTokens[audience].toLocaleString()})`);
   134→
   135→  return text;
   136→}
   137→

