    55→              initial={{ opacity: 0, scale: 0.9 }}
    56→              animate={{ opacity: 1, scale: 1 }}
    57→              className="flex flex-col items-center gap-6"
    58→            >
    59→              <img
    60→                src="/fuji-logo.png"
    61→                alt="Fuji Cafe"
    62→                className="h-32 md:h-40 w-auto object-contain"
    63→              />
    64→              <div className="flex flex-col items-center gap-2">
    65→                <div className="w-20 h-[2px] bg-gradient-to-r from-transparent via-[#E8637A] to-transparent animate-pulse" />
