   110→// ─── Smart rule-based fallback when Kimi is unavailable ───────────────────────
   111→export function smartAdvisorFallback(
   112→  userMessage: string,
   113→  products: any[]
   114→): { response: string; products: AdvisorProductRef[] } {
   115→  const lang = detectLang(userMessage);
   116→  const text = userMessage.toLowerCase();
   117→  const has = (...words: string[]) => words.some(w => text.includes(w));
   118→
   119→  const score = (p: any): number => {
   120→    const blob = `${p.name || ""} ${p.nameEn || ""} ${p.description || ""} ${p.descriptionEn || ""} ${(p.notes || []).join(" ")} ${(p.tags || []).join(" ")}`.toLowerCase();
   121→    let s = 0;
   122→    if (has("عود", "oud")) s += blob.includes("عود") || blob.includes("oud") ? 6 : 0;
   123→    if (has("ورد", "rose", "زهر")) s += blob.includes("ورد") || blob.includes("rose") || blob.includes("زهر") ? 5 : 0;
   124→    if (has("مسك", "musk")) s += blob.includes("مسك") || blob.includes("musk") ? 5 : 0;
   125→    if (has("صيف", "خفيف", "summer", "light", "نهار", "day")) s += blob.includes("خفيف") || blob.includes("منعش") || blob.includes("fresh") || blob.includes("light") ? 4 : 0;
   126→    if (has("شتاء", "ثقيل", "قوي", "winter", "strong", "ليل", "night")) s += blob.includes("ثقيل") || blob.includes("فخم") || blob.includes("قوي") || blob.includes("strong") || blob.includes("intense") ? 4 : 0;
   127→    if (has("عمل", "دوام", "مكتب", "work", "office", "هادئ")) s += blob.includes("هادئ") || blob.includes("راقي") || blob.includes("elegant") ? 3 : 0;
   128→    if (has("مناسبة", "حفل", "زفاف", "occasion", "wedding", "event", "فاخر")) s += blob.includes("فاخر") || blob.includes("luxur") ? 4 : 0;
   129→    if (has("رجال", "رجل", "men", "man")) s += (p.gender === "male" || blob.includes("رجال") || blob.includes("men")) ? 5 : 0;
   130→    if (has("نساء", "نسائي", "women", "woman", "بنات")) s += (p.gender === "female" || blob.includes("نسائ") || blob.includes("women")) ? 5 : 0;
   131→    if (has("هدية", "gift")) s += (p.featured || p.bestseller) ? 4 : 0;
   132→    if (p.featured) s += 1;
   133→    if (p.bestseller) s += 1;
   134→    return s;
   135→  };
   136→
   137→  const ranked = products
   138→    .filter(p => Number(p.price) > 0 || (Array.isArray(p.variants) && p.variants.some((v: any) => Number(v.price) > 0)))
   139→    .map(p => ({ p, s: score(p) }))
   140→    .sort((a, b) => b.s - a.s);
   141→  const top = ranked.slice(0, 3);
   142→
   143→  const refs: AdvisorProductRef[] = top.map(({ p }) => {
   144→    const variants: any[] = Array.isArray(p.variants) ? p.variants.filter((v: any) => Number(v.price) > 0) : [];
   145→    const minPrice = variants.length > 0 ? Math.min(...variants.map((v: any) => Number(v.price))) : Number(p.price) || 0;
   146→    return {
   147→      id: String(p.id || p._id),
   148→      name: p.name,
   149→      price: minPrice,
   150→      image: Array.isArray(p.images) ? p.images[0] : undefined,
   151→    };
   152→  });
   153→
   154→  const names = refs.map(r => r.name).join(lang === "ar" ? "، " : ", ");
   155→  const response = lang === "ar"
   156→    ? (refs.length > 0
   157→        ? `بناءً على ما ذكرت، أرشّح لك من تشكيلة فوجي كافيه: ${names} ✨\nهذه اختيارات مثالية وتحظى بإعجاب عملائنا. اضغط على أي منها لمعرفة التفاصيل أو إضافته للسلة مباشرة.`
   158→        : "أهلاً بك في فوجي كافيه ✨ أخبرني أكثر عن ذوقك (هل تفضل العود، الورد، المسك؟ للنهار أم الليل؟) وسأرشّح لك العطر المثالي.")
   159→    : (refs.length > 0
   160→        ? `Based on what you mentioned, I recommend from Fuji Cafe: ${names} ✨\nThese are excellent picks loved by our customers. Tap any to view details or add to cart.`
   161→        : "Welcome to Fuji Cafe ✨ Tell me more about your taste (do you prefer oud, rose, musk? day or night?) and I'll suggest the perfect scent.");
   162→
   163→  return { response, products: refs };
   164→}
