   166→export async function perfumeAdvisor(
   167→  userMessage: string,
   168→  conversationHistory: ChatMessage[],
   169→  products: any[]
   170→): Promise<{ response: string; products: AdvisorProductRef[] }> {
   171→  const lang = detectLang(userMessage);
   172→  const indexed = products.map((p, i) => ({ tag: `P${i + 1}`, product: p }));
   173→  const productList = indexed.map(({ tag, product: p }) => {
   174→    const variants: any[] = Array.isArray(p.variants) ? p.variants.filter((v: any) => Number(v.price) > 0) : [];
   175→    const aiExtra = (p.aiNotes || "").trim();
   176→    if (lang === "ar") {
   177→      const priceInfo = variants.length > 0
   178→        ? variants.map((v: any) => `${v.color} (${v.size}): ${Number(v.price).toLocaleString("ar-SA")} ر.س`).join("، ")
   179→        : `${p.price} ر.س`;
   180→      const base = `[${tag}] ${p.name} — ${(p.description || "").slice(0, 120)} | الأسعار: ${priceInfo}`;
   181→      return aiExtra ? `${base}\n   🧠 معلومات إضافية: ${aiExtra.slice(0, 250)}` : base;
   182→    } else {
   183→      const priceInfo = variants.length > 0
   184→        ? variants.map((v: any) => `${v.color} (${v.size}): ${v.price} SAR`).join(", ")
   185→        : `${p.price} SAR`;
   186→      const base = `[${tag}] ${p.nameEn || p.name} — ${(p.descriptionEn || p.description || "").slice(0, 120)} | Prices: ${priceInfo}`;
   187→      return aiExtra ? `${base}\n   🧠 AI context: ${aiExtra.slice(0, 250)}` : base;
   188→    }
   189→  }).join("\n");
   190→
   191→  const base = lang === "ar" ? PERFUME_SYSTEM_PROMPT_AR : PERFUME_SYSTEM_PROMPT_EN;
   192→  const catalogHeader = lang === "ar" ? "**المنتجات المتاحة حالياً (كل منتج له رمز [P#]):**" : "**Available products (each has a [P#] code):**";
   193→  const noProducts = lang === "ar" ? "لا توجد منتجات متاحة حالياً" : "No products currently available";
   194→  const extraRules = lang === "ar"
   195→    ? `**قاعدة إلزامية لا تنساها أبداً:**
   196→- في كل رد تقترح فيه منتجاً، يجب أن تكتب رمزه بصيغة [PRODUCT:P#] داخل النص.
   197→- مثال صحيح: "أرشّح لك عطر هبنوتك سينت [PRODUCT:P1] الذي يناسب ذوقك"
   198→- مثال آخر: "تجد رقياً مع [PRODUCT:P5] أو جرأةً مع [PRODUCT:P12]"
   199→- استخدم الأرقام الموجودة في القائمة بالضبط (P1, P2, P3, ...، لا تخترع رقماً)
   200→- اقترح من 1 إلى 3 منتجات كحد أقصى لكل رد
   201→- اقترح فقط من القائمة أعلاه ولا تخترع منتجات
   202→- عندما يسأل العميل عن السعر، اذكر جميع الخيارات (الحجم واللون والسعر)
   203→- بدون [PRODUCT:P#] لن تظهر بطاقة المنتج للعميل!`
   204→    : `**Mandatory rule, never forget:**
   205→- In every reply where you recommend a product, you MUST write its code as [PRODUCT:P#] inside the text.
   206→- Correct example: "I'd suggest Hypnotic Scent [PRODUCT:P1] which matches your taste"
   207→- Another: "You'll find elegance with [PRODUCT:P5] or boldness with [PRODUCT:P12]"
   208→- Use the exact numbers from the catalog (P1, P2, P3, ...) — never invent a number
   209→- Recommend 1–3 products max per reply
   210→- ONLY recommend from the catalog above — never invent products
   211→- When asked about price, list ALL variants (size, color, price)
   212→- Without [PRODUCT:P#] the product card won't appear for the customer!`;
   213→
   214→  const systemMsg = `${base}${LANG_DIRECTIVE(lang)}
   215→
   216→${catalogHeader}
   217→${productList || noProducts}
   218→
   219→${extraRules}`;
   220→
   221→  const messages: ChatMessage[] = [
   222→    { role: "system", content: systemMsg },
   223→    ...conversationHistory.slice(-10),
   224→    { role: "user", content: userMessage },
   225→  ];
   226→
   227→  // Try Kimi first, fall back to smart fallback if unavailable
   228→  let raw: string;
   229→  try {
   230→    raw = await groqChat(messages, 1024, "customer");
   231→  } catch (err: any) {
   232→    console.warn("[AI] Kimi unavailable for perfumeAdvisor, using smartFallback:", err?.message);
   233→    return smartAdvisorFallback(userMessage, products);
   234→  }
   235→
   236→  const refs: AdvisorProductRef[] = [];
   237→  const seen = new Set<string>();
   238→  const refRegex = /\[PRODUCT:([^\]]+)\]/g;
   239→  let match: RegExpExecArray | null;
   240→  while ((match = refRegex.exec(raw)) !== null) {
   241→    const token = match[1].trim();
   242→    let product: any = null;
   243→    const pMatch = /^P(\d+)$/i.exec(token);
   244→    if (pMatch) {
   245→      const idx = parseInt(pMatch[1], 10) - 1;
   246→      if (idx >= 0 && idx < indexed.length) product = indexed[idx].product;
   247→    }
   248→    if (!product) product = products.find(p => String(p.id || p._id) === token);
   249→    if (!product) continue;
   250→    const realId = String(product.id || product._id);
   251→    if (seen.has(realId)) continue;
   252→    seen.add(realId);
   253→    const variants: any[] = Array.isArray(product.variants) ? product.variants.filter((v: any) => Number(v.price) > 0) : [];
   254→    const minVariantPrice = variants.length > 0 ? Math.min(...variants.map((v: any) => Number(v.price))) : null;
   255→    refs.push({
   256→      id: realId,
   257→      name: product.name,
   258→      price: minVariantPrice ?? product.price,
   259→      image: Array.isArray(product.images) ? product.images[0] : undefined,
   260→    });
   261→  }
   262→  const response = raw
   263→    .replace(refRegex, "")
   264→    .replace(/\s*[,،]\s*([،,.!؟?])/g, "$1")
   265→    .replace(/\(\s*\)/g, "")
   266→    .replace(/\s+([،,.!؟?])/g, "$1")
   267→    .replace(/\s+/g, " ")
   268→    .trim();
   269→  return { response, products: refs };
   270→}
