    31→async function sendEmail(params: {
    32→  to: string;
    33→  toName?: string;
    34→  subject: string;
    35→  html: string;
    36→  text?: string;
    37→  /**
    38→   * Optional file attachments. SMTP2GO accepts base64-encoded blobs via the
    39→   * `attachments` field (each item: { filename, fileblob, mimetype }).
    40→   * We accept the more conventional Nodemailer-style shape and translate it.
    41→   */
    42→  attachments?: Array<{ filename: string; content: string; contentType?: string }>;
    43→}): Promise<{ success: boolean; error?: string }> {
    44→  const { apiKey, sender, senderName } = getCredentials();
    45→
    46→  try {
    47→    const res = await fetch(SMTP2GO_API, {
    48→      method: "POST",
    49→      headers: { "Content-Type": "application/json" },
    50→      body: JSON.stringify({
    51→        api_key: apiKey,
    52→        to: [`${params.toName || ""} <${params.to}>`],
    53→        sender: `${senderName} <${sender}>`,
    54→        subject: params.subject,
    55→        html_body: params.html,
    56→        text_body: params.text || "",
    57→        ...(params.attachments && params.attachments.length > 0
    58→          ? {
    59→              attachments: params.attachments.map((a) => ({
    60→                filename: a.filename,
    61→                fileblob: a.content, // already base64-encoded by caller
    62→                mimetype: a.contentType || "application/octet-stream",
    63→              })),
    64→            }
    65→          : {}),
    66→      }),
    67→    });
    68→
    69→    const data = await res.json();
    70→
    71→    if (!res.ok || data.data?.error) {
    72→      const errMsg = data.data?.error || `HTTP ${res.status}`;
    73→      console.error("[Email] SMTP2GO error:", errMsg);
    74→      return { success: false, error: errMsg };
    75→    }
    76→
    77→    console.log(`[Email] ✅ Sent to ${params.to} — Subject: ${params.subject}`);
    78→    return { success: true };
    79→  } catch (err: any) {
