   167→    "طريقة الدفع", "تاريخ الإنشاء", "تاريخ التسليم",
   168→  ];
   169→  const rows = orders.map(o => [
   170→    `#${(o.id || "").slice(-6).toUpperCase()}`,
   171→    o.pickupCode || "",
   172→    o.status || "",
   173→    o.shippingMethod === "pickup" ? "استلام" : "توصيل",
   174→    o.customerName || "",
   175→    o.customerPhone || "",
   176→    (o.deliveryAddress || "").replace(/[\r\n]+/g, " "),
   177→    (o.items || []).length,
   178→    Number(o.subtotal || 0).toFixed(2),
   179→    Number(o.shippingCost || 0).toFixed(2),
   180→    Number(o.vatAmount || 0).toFixed(2),
   181→    Number(o.total || 0).toFixed(2),
   182→    o.paymentMethod || "",
   183→    o.createdAt ? new Date(o.createdAt).toLocaleString("ar-SA") : "",
   184→    o.verifiedAt ? new Date(o.verifiedAt).toLocaleString("ar-SA") : "",
   185→  ]);
   186→  const escape = (v: any) => {
   187→    const s = String(v ?? "");
   188→    if (s.includes(",") || s.includes('"') || s.includes("\n")) {
   189→      return `"${s.replace(/"/g, '""')}"`;
   190→    }
   191→    return s;
   192→  };
   193→  // BOM so Excel opens UTF-8 correctly
   194→  const csv = "\uFEFF" + [headers, ...rows].map(r => r.map(escape).join(",")).join("\r\n");
   195→  const blob = new Blob([csv], { type: "text/csv;charset=utf-8" });
   196→  const url = URL.createObjectURL(blob);
   197→  const a = document.createElement("a");
   198→  a.href = url;
   199→  a.download = filename;
   200→  a.click();
