import express from "express";
import { createServer } from "http";
import { WebSocketServer } from "ws";
import { connectDB } from "./db";
import { registerRoutes } from "./routes";
import { registerWsClient } from "./notifications";
import { serveStatic, setupVite } from "./vite";

const app = express();
const httpServer = createServer(app);

app.use(express.json({ limit: "50mb" }));
app.use(express.urlencoded({ extended: true, limit: "50mb" }));

process.on("uncaughtException", (err) => {
  console.error("[Server] Uncaught exception:", err.message);
  // Do NOT exit — keep server alive
});

(async () => {
  await connectDB();

  // ─── One-time migration: set correct legal / VAT data ─────────────────────
  try {
    const { StoreSettingsModel } = await import("./models");
    await StoreSettingsModel.updateOne(
      { key: "main" },
      {
        $set: {
          crNumber: "7042488606",
          nationalUnifiedNumber: "7042488606",
          crLink: "https://qr.saudibusiness.gov.sa/viewcr?nCrNumber=HdI7BQp2aUmM4b9xJYrbnA==",
          vatNumber: "312650651100003",
        },
        $setOnInsert: { key: "main" },
      },
      { upsert: true }
    );
    console.log("[Migration] Store legal data updated");
  } catch (e: any) {
    console.warn("[Migration] Could not update store legal data:", e?.message);
  }

  // ─── Seed: Fuji Al-Suwaidi pickup branch ──────────────────────────────────
  try {
    const { BranchModel } = await import("./models");
    const exists = await BranchModel.findOne({ slug: "suwaidi" });
    if (!exists) {
      await BranchModel.create({
        name: "فوجي السويدي",
        nameEn: "Fuji Al-Suwaidi",
        slug: "suwaidi",
        city: "الرياض",
        address: "حي السويدي، الرياض",
        phone: "",
        hours: "السبت – الخميس: ٧ص – ١١م  |  الجمعة: ٢م – ١١م",
        pickupHours: "السبت – الخميس: ٧ص – ١١م  |  الجمعة: ٢م – ١١م",
        lat: 24.6270,
        lng: 46.6741,
        mapUrl: "https://maps.app.goo.gl/ndQdByUPWBU9pcjN8",
        isActive: true,
        pickupEnabled: true,
        image: "",
        sortOrder: 0,
      });
      console.log("[Seed] Fuji Al-Suwaidi branch created");
    } else {
      // Update map URL if branch already exists
      await BranchModel.updateOne(
        { slug: "suwaidi" },
        { $set: { mapUrl: "https://maps.app.goo.gl/ndQdByUPWBU9pcjN8" } }
      );
    }
  } catch (e: any) {
    console.warn("[Seed] Could not create Al-Suwaidi branch:", e?.message);
  }

  await registerRoutes(httpServer, app);

  // ─── WebSocket Server ──────────────────────────────────────────────────────
  // Attach WS on /ws path so it doesn't interfere with Vite's HMR websocket
  const wss = new WebSocketServer({ server: httpServer, path: "/ws" });
  wss.on("connection", (ws, req) => {
    // Client must send { type: "auth", userId: "..." } within 3s
    let authTimeout = setTimeout(() => ws.terminate(), 3000);
    ws.on("message", (raw) => {
      try {
        const msg = JSON.parse(raw.toString());
        if (msg.type === "auth" && msg.userId) {
          clearTimeout(authTimeout);
          registerWsClient(msg.userId, ws);
          ws.send(JSON.stringify({ type: "auth_ok" }));
        }
      } catch {
        // ignore malformed messages
      }
    });
    ws.on("error", () => {});
  });
  console.log("[WS] WebSocket server ready on /ws");

  if (process.env.NODE_ENV === "production") {
    serveStatic(app);
  } else {
    await setupVite(app, httpServer);
  }

  const PORT = Number(process.env.PORT || 5000);
  httpServer.listen(PORT, "0.0.0.0", () => {
    console.log(`${new Date().toLocaleTimeString()} [express] serving on port ${PORT}`);
  });
})();

