   108→// Short, attention-grabbing beep for new-order alerts (~0.5s, 3-tone)
   109→// Returns a promise that resolves when the sound has been initiated.
   110→async function playBeep(): Promise<void> {
   111→  try {
   112→    const ctx = getAudioCtx();
   113→    if (!ctx) return;
   114→    // Resume the context if it was suspended (required on Safari/iOS)
   115→    if (ctx.state === "suspended") await ctx.resume();
   116→    const beepOnce = (when: number, freq: number) => {
   117→      const osc = ctx.createOscillator();
   118→      const gain = ctx.createGain();
   119→      osc.type = "sine";
   120→      osc.frequency.value = freq;
   121→      gain.gain.setValueAtTime(0.0001, ctx.currentTime + when);
   122→      gain.gain.exponentialRampToValueAtTime(0.4, ctx.currentTime + when + 0.02);
   123→      gain.gain.exponentialRampToValueAtTime(0.0001, ctx.currentTime + when + 0.20);
   124→      osc.connect(gain).connect(ctx.destination);
   125→      osc.start(ctx.currentTime + when);
   126→      osc.stop(ctx.currentTime + when + 0.22);
   127→    };
   128→    beepOnce(0,    880);
   129→    beepOnce(0.25, 1175);
   130→    beepOnce(0.50, 880);
   131→  } catch { /* ignore — never crash the UI */ }
