   147→function bulkPrintInvoices(orderIds: string[]) {
   148→  if (orderIds.length === 0) return;
   149→  // Open all windows SYNCHRONOUSLY inside the user gesture so popup blockers
   150→  // (Chrome/Safari) don't reject everything but the first. setTimeout breaks
   151→  // the gesture chain and causes blocked popups.
   152→  let blocked = 0;
   153→  for (const id of orderIds) {
   154→    const w = window.open(`/invoice/${id}?print=1`, `_print_${id}`, "noopener,noreferrer");
   155→    if (!w) blocked++;
   156→  }
   157→  if (blocked > 0) {
   158→    alert(`تم حظر ${blocked} نافذة بواسطة المتصفح. الرجاء السماح بالنوافذ المنبثقة لهذا الموقع وإعادة المحاولة.`);
   159→  }
   160→}
